<svg viewBox="0 0 700 720" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-family="sans-serif" font-size="16" font-weight="700">Institutional Futures 'Freeze' vs Spot ETF 'Reversal' vs a Quiet Derivatives Surface</text>
  <text x="20" y="48" fill="#a1a1aa" font-family="sans-serif" font-size="13">CFTC COT report (weekly) · Spot ETF flows (daily) · Derivatives metrics (as of July 14)</text>
  <text x="20" y="82" fill="#d4d4d8" font-family="sans-serif" font-size="14" font-weight="700">CME Futures Positioning (COT, weekly)</text>
  <rect x="20" y="96" width="320" height="120" rx="10" fill="#18181b" stroke="#3f3f46"/>
